svg.script:
function selectDistrict(district) {
  if (window.parent && window.parent.selectDistrict) {
    window.parent.selectDistrict(district);
  }
}
function hoverDistrict(el, isHover) {
  if (isHover) {
      el.setAttribute("fill-opacity", "0.9");
  } else {
      el.setAttribute("fill-opacity", "0.6");
  }
}
